VALUES
  ('social-worker-moex-06730', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '操作制約學習（operant conditioning）與社會學習（social learning）理論的比較，下列敘述何者正確？', '["二者都認為個體對自己有無能力達成目標的信念是學習的關鍵", "二者都認為行為不一定要親身經驗就可以學習", "二者都認為人們經由訊息處理過程可主動與環境產生互動", "二者都認為環境在個人學習上扮演重要角色"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "d2ee28ed3e24", "answer_pdf_sha1": "beeb8e1e0c62", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06731', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '個人不直接參與或介入之機構，但此機構對生活卻有著深遠影響，例如父母的工作場所可能會影響孩子 的生活，即使子女並不直接參與父母親的工作。請問「父母的工作場所」在Bronfenbrenner的生態模式中 稱為：', '["鉅視系統（macrosystem）", "外部系統（exosystem）", "中間系統（mesosystem）", "微視系統（microsystem）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "d2ee28ed3e24", "answer_pdf_sha1": "beeb8e1e0c62", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06732', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列那一個理論家所提出之觀點不是所謂「階段論」（Stage或Period）取向？', '["Albert Bandura", "Erik Erikson", "Sigmund Freud", "Jean Piaget"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "d2ee28ed3e24", "answer_pdf_sha1": "beeb8e1e0c62", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06733', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列關於產婦吸菸對胎兒的影響，何者錯誤？', '["會使孕婦血液裡的二氧化碳增加，減少胎兒氧氣量的獲取", "增加早產、胎兒死亡、流產的機率", "減少子宮內胎兒對外界的反應", "對胎兒的影響是長期的，到孩童時期可能個頭較小、有認知發展上的問題"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "d2ee28ed3e24", "answer_pdf_sha1": "beeb8e1e0c62", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06734', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列何者不是M. Ainsworth 所提出之依附類型？', '["穩固型依附（solid attachment）", "焦慮型依附（anxious attachment）", "迴避型依附（avoidant attachment）", "安全型依附（secure attachment）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "d2ee28ed3e24", "answer_pdf_sha1": "beeb8e1e0c62", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06735', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '年紀較小的兒童早期，會為了得到想要的東西（例如玩具）而踢或打，此種攻擊行為通常是那一類型的 攻擊？', '["替代性攻擊", "干擾性攻擊", "工具性攻擊", "敵對性攻擊"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "d2ee28ed3e24", "answer_pdf_sha1": "beeb8e1e0c62", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06736', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', 'Erikson認為青少年處於「心理的延期償付時期」（psychological moratorium），下列關於此概念的敘述， 何者正確？', '["認知發展的速度影響自我認同，因而出現延後現象", "正式運思期的思考特性，使得生理特徵變化造成的困擾得以緩解或補償", "青少年心理上的獨立自主需求，時常與父母管教方式產生衝突，阻礙其發展", "一方面追求兒童時期的安全感，另方面又追求成年期的自主性，產生矛盾"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "d2ee28ed3e24", "answer_pdf_sha1": "beeb8e1e0c62", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06737', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「中年危機」一詞常被用來形容某些中年人遭遇的處境，下列關於此一概念敘述，何者錯誤？', '["被視為是中年期的典型特徵", "此概念有很大影響力，主要因為社會大眾為了避開不確定感，仍偏好可預期和可觸摸的里程碑或發展階段", "很少實證上的證據支持「中年危機」這種說法", "原指中年人面臨同時撫養年長者與年幼者，壓力過大而產生焦慮甚至情緒崩潰，後來被廣泛應用分析 中年期的嚴重焦慮情形"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "d2ee28ed3e24", "answer_pdf_sha1": "beeb8e1e0c62", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06738', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '所謂「去幻象化」（de-illusionment）所指為何？', '["兒童早期事實與虛幻容易混在一起，到兒童中期慢慢能區分此二者", "是具體運思期的特徵，所有的認知乃立基於具象經驗，而非假設性抽象思維", "中年人經歷許多事與願違情形，喪失某些對人和過去所持守的信念，較為務實看待人生", "是老年人檢視過去夢想達成情形、自我統整的方法與過程"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "d2ee28ed3e24", "answer_pdf_sha1": "beeb8e1e0c62", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06739', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關新生兒的特性，下列何者錯誤?', '["由陰道產出與由剖腹產方式出生的新生兒頭形通常不太一樣", "皮膚略呈紅色，光滑柔嫩", "已有反射動作", "一般的新生兒手腳略呈青色"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "d2ee28ed3e24", "answer_pdf_sha1": "beeb8e1e0c62", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
